<?php require_once "../config/database.php"; require_once "../includes/session.php"; requireAdmin(); 
if(isset($_GET['hide']))$conn->prepare("UPDATE reviews SET status=IF(status='Visible','Hidden','Visible') WHERE review_id=?")->execute([$_GET['hide']]);include "../includes/header.php";$rows=$conn->query("SELECT reviews.*,users.full_name,rooms.room_name FROM reviews JOIN users ON reviews.user_id=users.user_id JOIN rooms ON reviews.room_id=rooms.room_id ORDER BY review_id DESC")->fetchAll(PDO::FETCH_ASSOC);?><div class="container"><h1 class="section-title">Reviews</h1><div class="table-wrap"><table><tr><th>Tenant</th><th>Room</th><th>Rating</th><th>Comment</th><th>Status</th><th>Action</th></tr><?php foreach($rows as $r):?><tr><td><?=e($r['full_name'])?></td><td><?=e($r['room_name'])?></td><td><?=$r['rating']?></td><td><?=e($r['comment'])?></td><td><?=$r['status']?></td><td><a class="btn danger" href="?hide=<?=$r['review_id']?>">Hide/Show</a></td></tr><?php endforeach;?></table></div></div><?php include "../includes/footer.php";?>
